  3	  APP_NAMESPACE_ANNOTATION,
  4	  CONSISTENCY_GROUP_LABEL,
  5	  ReplicationType,
  6	  VolumeReplicationHealth,
  7	} from '@odf/mco/constants';
  8	import {
  9	  ACMManagedClusterViewKind,
 10	  DRPlacementControlKind,
 11	  DRVolumeReplicationGroupKind,
 12	} from '@odf/mco/types';
 13	import { getReplicationHealth } from '@odf/mco/utils';
 14	import {
 15	  ACMManagedClusterViewModel,
 16	  getAnnotations,
 17	  getName,
 18	  GreenCheckCircleIcon,
 19	  ModalBody,
 20	  RedExclamationCircleIcon,
 21	  StatusBox,
 22	  useCustomTranslation,
 23	} from '@odf/shared';
 24	import { referenceForModel } from '@odf/shared/utils';
 25	import {
 26	  K8sResourceCommon,
 27	  WatchK8sResultsObject,
 28	} from '@openshift-console/dynamic-plugin-sdk';
 29	import { TFunction } from 'react-i18next';
 30	import {
 31	  Button,
 32	  ButtonVariant,
 33	  Divider,
 34	  Flex,
 35	  FlexItem,
 36	  SearchInput,
 37	  Text,
 38	  TextVariants,
 39	} from '@patternfly/react-core';
 40	import { DRPlacementControlType } from '../utils/types';
 41	
 42	export type ConsistencyGroupInfo = {
 43	  name: string;
 44	  namespace: string;
 45	  lastSyncTime: string;
 46	  pvcs: string[];
 47	  synced: boolean;
 48	};
 49	
 50	export type WatchResourceType = {
 51	  [key in string]: ACMManagedClusterViewKind;
 52	};
 53	
 54	const filterGroups = (groups: ConsistencyGroupInfo[], searchValue: string) => {
 55	  const lowerSearch = searchValue.toLowerCase();
 56	  const matchesSearch = (text: string) =>
 57	    text.toLowerCase().includes(lowerSearch);
 58	  return groups.filter(({ name, namespace, pvcs }) =>
 59	    [name, namespace, ...pvcs].some(matchesSearch)
 60	  );
 61	};
 62	
 63	const GroupInfo: React.FC<GroupInfoProps> = ({ group, t }) => (
 64	  <Flex
 65	    justifyContent={{ default: 'justifyContentSpaceBetween' }}
 66	    alignItems={{ default: 'alignItemsCenter' }}
 67	  >
 68	    <FlexItem>
 69	      <Text component={TextVariants.h5}>
 70	        {t('Group name: {{ groupName }}', { groupName: group.name })}
 71	      </Text>
 72	    </FlexItem>
 73	    {group.synced ? (
 74	      <FlexItem>
 75	        <GreenCheckCircleIcon /> {t('Synced')}, {group.lastSyncTime}
 76	      </FlexItem>
 77	    ) : (
 78	      <FlexItem>
 79	        <RedExclamationCircleIcon /> {t('Sync failed')}, {group.lastSyncTime}
 80	      </FlexItem>
 81	    )}
 82	  </Flex>
 83	);
 84	
 85	const NamespaceInfo: React.FC<NamespaceInfoProps> = ({ t, namespace }) => {
 86	  return (
 87	    <div className="pf-v6-u-mt-md">
 88	      <Text component={TextVariants.h6}>{t('Namespace')}</Text>
 89	      <Text>{namespace}</Text>
 90	    </div>
 91	  );
 92	};
 93	
 94	const PVCList: React.FC<PVCInfoProps> = ({ pvcs, t }) => {
 95	  const [showAll, setShowAll] = React.useState(false);
 96	  const maxVisiblePVCs = 7;
 97	  const hasMorePVCs = pvcs.length > maxVisiblePVCs;
 98	  const remainingCount = pvcs.length - maxVisiblePVCs;
 99	
100	  const visiblePVCs = showAll ? pvcs : pvcs.slice(0, maxVisiblePVCs);
101	
102	  return (
103	    <div className="pf-v6-u-mt-md">
104	      <Text component={TextVariants.h6}>{t('Persistent volume claims')}</Text>
105	      <Text component={TextVariants.p}>
106	        {visiblePVCs.join(', ')}
107	        {hasMorePVCs && (
108	          <>
109	            {' '}
110	            <Button
111	              variant={ButtonVariant.link}
112	              onClick={() => setShowAll((prev) => !prev)}
113	              isInline
114	              className="pf-v6-u-ml-sm"
115	            >
116	              {showAll
117	                ? t('Show less')
118	                : t('{{count}} more', { count: remainingCount })}
119	            </Button>
120	          </>
121	        )}
122	      </Text>
123	    </div>
124	  );
125	};
126	
127	const GroupCard: React.FC<GroupCardProps> = ({ group, isLast, t }) => (
128	  <div key={group.name} className="pf-v6-u-mb-lg">
129	    <GroupInfo group={group} t={t} />
130	    <NamespaceInfo namespace={group.namespace} t={t} />
131	    <PVCList pvcs={group.pvcs} t={t} />
132	    {!isLast && <Divider className="pf-v6-u-mt-md pf-v6-u-mb-md" />}
133	  </div>
134	);
135	
136	const GroupList: React.FC<GroupListProps> = ({ filteredGroups, t }) => (
137	  <div>
138	    {filteredGroups.length > 0 ? (
139	      filteredGroups.map((group, index) => (
140	        <GroupCard
141	          key={group.name}
142	          group={group}
143	          isLast={index === filteredGroups.length - 1}
144	          t={t}
145	        />
146	      ))
147	    ) : (
148	      <Text>{t('No volume consistency groups match your search')}</Text>
149	    )}
150	  </div>
151	);
152	
153	const NoConsistencyGroups: React.FC = () => {
154	  const { t } = useCustomTranslation();
155	
156	  return (
157	    <Text className="pf-v6-u-text-align-center pf-v6-u-mt-lg">
158	      {t('No volume consistency groups found for this application')}
159	    </Text>
160	  );
161	};
162	
163	export const ConsistencyGroupsContent: React.FC<
164	  ConsistencyGroupsContentProps
165	> = ({ consistencyGroups, loaded, loadError }) => {
166	  const { t } = useCustomTranslation();
167	  const [searchValue, setSearchValue] = React.useState('');
168	
169	  const filteredGroups = React.useMemo(
170	    () => filterGroups(consistencyGroups, searchValue),
171	    [consistencyGroups, searchValue]
172	  );
173	
174	  const handleSearchChange = (value: string) => {
175	    setSearchValue(value);
176	  };
177	
178	  return (
179	    <ModalBody>
180	      <StatusBox
181	        loaded={loaded}
182	        loadError={loadError}
183	        EmptyMsg={NoConsistencyGroups}
184	        data={consistencyGroups}
185	      >
186	        <Text component={TextVariants.h3} className="pf-v6-u-mb-md">
187	          {t('Volume consistency groups')}
188	        </Text>
189	
190	        <Flex className="pf-v6-u-mb-lg">
191	          <FlexItem grow={{ default: 'grow' }}>
192	            <SearchInput
193	              placeholder={t(
194	                'Search by group name, PVC name, or PVC namespace'
195	              )}
196	              value={searchValue}
197	              onChange={(_event, value) => handleSearchChange(value)}
198	              onClear={() => handleSearchChange('')}
199	            />
200	          </FlexItem>
201	        </Flex>
202	
203	        <GroupList filteredGroups={filteredGroups} t={t} />
204	      </StatusBox>
205	    </ModalBody>
206	  );
207	};
208	
209	const buildConsistencyGroupMap = (
210	  vrg: DRVolumeReplicationGroupKind
211	): Map<string, ConsistencyGroupInfo> => {
212	  const cgMap = new Map<string, ConsistencyGroupInfo>();
213	  const protectedPVCs = vrg.status?.protectedPVCs || [];
214	
215	  protectedPVCs.forEach((pvc) => {
216	    const cgLabel = Object.entries(pvc.labels || {}).find(
217	      ([key]) => key === CONSISTENCY_GROUP_LABEL
218	    );
219	    if (!cgLabel) return;
220	
221	    const cgName = cgLabel[1] as string;
222	    const schedulingInterval = vrg.spec.async?.schedulingInterval;
223	    const dataLastSyncedOn = pvc.lastSyncTime;
224	    const healthStatus = getReplicationHealth(
225	      dataLastSyncedOn || '',
226	      schedulingInterval,
227	      ReplicationType.ASYNC
228	    );
229	    const isSynced = healthStatus === VolumeReplicationHealth.HEALTHY;
230	
231	    // Use composite key to support consistency groups across multiple namespaces
232	    const cgKey = `${pvc.namespace}/${cgName}`;
233	
234	    if (!cgMap.has(cgKey)) {
235	      cgMap.set(cgKey, {
236	        name: cgName,
237	        pvcs: [],
238	        namespace: pvc.namespace,
239	        lastSyncTime: pvc.lastSyncTime,
240	        synced: isSynced,
241	      });
242	    }
243	
244	    cgMap.get(cgKey).pvcs.push(pvc.name);
245	  });
246	
247	  return cgMap;
248	};
249	
250	const convertCGMapToGroups = (cgMap: Map<string, ConsistencyGroupInfo>) => {
251	  const groups = [];
252	  cgMap.forEach((value, _) => {
253	    groups.push({
254	      name: value.name,
255	      namespace: value.namespace,
256	      lastSyncTime: value.lastSyncTime,
257	      pvcs: value.pvcs,
258	      synced: value.synced,
259	    });
260	  });
261	  return groups;
262	};
263	
264	const extractVRGFromMCV = (mcvData): DRVolumeReplicationGroupKind | null =>
265	  mcvData.data?.status?.result as DRVolumeReplicationGroupKind;
266	
267	export const extractConsistencyGroups = (mcvs: {
268	  [key in string]: WatchK8sResultsObject<K8sResourceCommon>;
269	}): { loaded: boolean; loadError: any; data: ConsistencyGroupInfo[] } => {
270	  let allLoaded = true;
271	  let anyError = '';
272	  const groups: ConsistencyGroupInfo[] = [];
273	
274	  Object.values(mcvs).forEach((mcvData) => {
275	    if (mcvData.loadError && !anyError) {
276	      anyError = mcvData.loadError;
277	    }
278	
279	    if (!mcvData.loaded) {
280	      allLoaded = false;
281	    }
282	
283	    if (!mcvData.loaded || mcvData.loadError || !mcvData.data) return;
284	
285	    const vrg = extractVRGFromMCV(mcvData);
286	    if (!vrg) return;
287	
288	    const cgMap = buildConsistencyGroupMap(vrg);
289	    const vrgGroups = convertCGMapToGroups(cgMap);
290	    groups.push(...vrgGroups);
291	  });
292	
293	  return {
294	    loaded: allLoaded,
295	    loadError: anyError,
296	    data: groups,
297	  };
298	};
299	
300	export const getMCVName = (
301	  resource: DRPlacementControlKind | DRPlacementControlType
302	): string => {
303	  const annotations = getAnnotations(resource, {});
304	  const ns = annotations[APP_NAMESPACE_ANNOTATION] ?? '';
305	  return `${getName(resource)}-${ns}-vrg-mcv`;
306	};
307	
308	export const buildMCVResource = (clusterName: string, mcvName: string) => {
309	  return {
310	    kind: referenceForModel(ACMManagedClusterViewModel),
311	    namespace: clusterName,
312	    name: mcvName,
313	  };
314	};
315	
316	export type ConsistencyGroupsContentProps = {
317	  consistencyGroups: ConsistencyGroupInfo[];
318	  namespace?: string;
319	  loaded: boolean;
320	  loadError: any;
321	};
322	
323	type GroupInfoProps = {
324	  group: ConsistencyGroupInfo;
325	  t: TFunction<string>;
326	};
327	
328	type NamespaceInfoProps = {
329	  namespace: string;
330	  t: TFunction<string>;
331	};
332	
333	type PVCInfoProps = {
334	  pvcs: string[];
335	  t: TFunction<string>;
336	};
337	
338	type GroupCardProps = {
339	  group: ConsistencyGroupInfo;
340	  isLast: boolean;
341	  t: TFunction<string>;
342	};
343	
344	type GroupListProps = {
345	  filteredGroups: ConsistencyGroupInfo[];
346	  t: TFunction<string>;
347	};

